mapper.select:
select * from nx_community_dispatch_plan
where nx_cdp_community_id = #{communityId}
  and nx_cdp_route_date = #{routeDate}
limit 1

mapper.update:
update nx_community_dispatch_plan
nx_cdp_status = #{nxCdpStatus}, nx_cdp_depot_lat = #{nxCdpDepotLat}, nx_cdp_depot_lng = #{nxCdpDepotLng},
where nx_community_dispatch_plan_id = #{nxCommunityDispatchPlanId}
